from elasticsearch import Elasticsearch
import json

def execute_dynamic_aggregation(script_code, index_name):
    es = Elasticsearch([{'host': 'localhost', 'port': 9200}])
    
    body = {
        "aggs": {
            "dynamic_agg": {
                "scripted_metric": {
                    "init_script": "state.sum = 0",
                    "map_script": script_code,
                    "combine_script": "return state.sum",
                    "reduce_script": "double sum = 0; for (int i = 0; i < states.length; i++) { sum += states[i]; } return sum;"
                }
            }
        }
    }
    
    try:
        response = es.search(index=index_name, body=body, request_cache=False)
        return response
    except Exception as e:
        return {"error": str(e)}

def main():
    # Example usage
    script_code = "state.sum += doc['value'].value"
    index_name = "your_index"
    
    result = execute_dynamic_aggregation(script_code, index_name)
    print(json.dumps(result, indent=2))

if __name__ == "__main__":
    main()